// // This module implements a 4-input combinational logic function that outputs X based on the specified logic expression. The output X is determined by the inputs A1, A2, A3, and B1, specifically evaluating to false when A1 is high while A2 is low, or when A1 and A2 are both high while A3 is also high, or when A1 is low and A2 is low while B1 is high.
module top_module(
    X   ,
    A1  ,
    A2  ,
    A3  ,
    B1  ,
    VPWR,
    VGND,
    VPB ,
    VNB
);output X   ;
    input  A1  ;
    input  A2  ;
    input  A3  ;
    input  B1  ;
    input  VPWR;
    input  VGND;
    input  VPB ;
    input  VNB ;

    assign X = ((A1 & ~A2) | (A1 & A2 & A3) | (~A1 & ~A2 & B1));

endmodule
